export default function TestimonialSection() {
  const [current, setCurrent] = useState(0)
  const [visibleSlides, setVisibleSlides] = useState(3)

  const autoPlayRef = useRef<any>(null)

  useEffect(() => {
    const handleResize = () => {
      if (window.innerWidth < 640) setVisibleSlides(1)
      else if (window.innerWidth < 1024) setVisibleSlides(2)
      else setVisibleSlides(3)
    }

    handleResize()
    window.addEventListener("resize", handleResize)
    return () => window.removeEventListener("resize", handleResize)
  }, [])

  // ✅ FIXED NEXT
  const nextSlide = () => {
    setCurrent((prev) => {
      if (prev >= testimonials.length - visibleSlides) {
        return 0
      }
      return prev + 1
    })
  }

  // ✅ FIXED PREV
  const prevSlide = () => {
    setCurrent((prev) => {
      if (prev === 0) {
        return testimonials.length - visibleSlides
      }
      return prev - 1
    })
  }

  // Autoplay
  useEffect(() => {
    autoPlayRef.current = setTimeout(() => {
      nextSlide()
    }, 5000)

    return () => clearTimeout(autoPlayRef.current)
  }, [current, visibleSlides])

  return (
    <section className="section-padding bg-white">
      <div className="container-main">

        {/* Header */}
        <div className="section-center mb-12">
          <p className="text-sm uppercase tracking-widest text-muted-foreground mb-2">
